enum BankError: Error {
    case insufficientFunds(requested: Double, available: Double)
    case negativeAmount
}

actor BankAccount {
    let accountNumber: String   // constant: never changes
    let owner: String           // constant: never changes
    private(set) var balance: Double    // mutable: needs protection

    init(accountNumber: String, owner: String, initialBalance: Double) {
        self.accountNumber = accountNumber
        self.owner = owner
        self.balance = initialBalance
    }

    func deposit(amount: Double) throws {
        guard amount > 0 else { throw BankError.negativeAmount }
        balance += amount
    }

    func withdraw(amount: Double) throws {
        guard amount > 0 else { throw BankError.negativeAmount }
        guard balance >= amount else {
            throw BankError.insufficientFunds(
                requested: amount,
                available: balance
            )
        }
        balance -= amount
    }

    func transfer(amount: Double, to other: BankAccount) async throws {
        guard amount > 0 else { throw BankError.negativeAmount }
        guard balance >= amount else {
            throw BankError.insufficientFunds(
                requested: amount,
                available: balance
            )
        }
        // Withdraw from self first, then deposit to the other account.
        // `other` is a different actor, so we need `await` to cross its boundary.
        balance -= amount
        try await other.deposit(amount: amount)
    }
}

// ❌ This won't compile:
let account = BankAccount(accountNumber: "001", owner: "Alice", initialBalance: 1000)
print(account.balance)  // Error: expression is 'async' but is not marked with 'await'

// ✅ Correct: always use await to cross the actor boundary
Task {
    let account = BankAccount(accountNumber: "001", owner: "Alice", initialBalance: 1000)
    print(await account.balance) // 1000.0
}

extension BankAccount: CustomStringConvertible {
    // accountNumber and owner are `let` constants, safe to access without await
    nonisolated var description: String {
        "Account \(accountNumber) (\(owner))"
    }
}

// ⚠️ Dangerous pattern: do NOT copy this into the playground
func buyTicket() async {
    guard balance >= 50 else { return }
    // Actor suspends here. Another call can run in the meantime.
    await processPayment()
    // By the time we resume, balance might already be less than 50!
    balance -= 50  // potential over-spend
}

// ✅ Our transfer method is safe because we deduct locally BEFORE awaiting the other actor
func transfer(amount: Double, to other: BankAccount) async throws {
    // ...
    balance -= amount            // local mutation first, no suspension yet
    try await other.deposit(amount: amount)  // suspension happens here, but local state is already committed
}

