import Foundation
// MARK: - Error
enum BankError: Error {
    case insufficientFunds(requested: Double, available: Double)
    case negativeAmount
}
// MARK: - Actor
actor BankAccount {
    let accountNumber: String
    let owner: String
    private(set) var balance: Double
    init(accountNumber: String, owner: String, initialBalance: Double) {
        self.accountNumber = accountNumber
        self.owner = owner
        self.balance = initialBalance
    }
    func deposit(amount: Double) throws {
        guard amount > 0 else { throw BankError.negativeAmount }
        balance += amount
    }
    func withdraw(amount: Double) throws {
        guard amount > 0 else { throw BankError.negativeAmount }
        guard balance >= amount else {
            throw BankError.insufficientFunds(
                requested: amount,
                available: balance
            )
        }
        balance -= amount
    }
    func transfer(amount: Double, to other: BankAccount) async throws {
        guard amount > 0 else { throw BankError.negativeAmount }
        guard balance >= amount else {
            throw BankError.insufficientFunds(
                requested: amount,
                available: balance
            )
        }
        balance -= amount
        try await other.deposit(amount: amount)
    }
}
// MARK: - CustomStringConvertible (nonisolated)
extension BankAccount: CustomStringConvertible {
    nonisolated var description: String {
        "Account \(accountNumber) (\(owner))"
    }
}
// MARK: - Playground Entry Point
// Playgrounds need a top-level async entry point.
// This is the standard way to run async code in a playground.
Task {
    let alice = BankAccount(accountNumber: "001", owner: "Alice", initialBalance: 1000)
    let bob   = BankAccount(accountNumber: "002", owner: "Bob",   initialBalance: 500)
    // nonisolated no await needed
    print("Accounts created:")
    print("  \(alice)")
    print("  \(bob)")
    // Read isolated state await required
    print("\nInitial balances:")
    print("  Alice: $\(await alice.balance)")
    print("  Bob:   $\(await bob.balance)")
    // Deposit
    try await alice.deposit(amount: 200)
    print("\nAfter Alice deposits $200:")
    print("  Alice: $\(await alice.balance)")
    // Withdraw
    try await bob.withdraw(amount: 100)
    print("\nAfter Bob withdraws $100:")
    print("  Bob: $\(await bob.balance)")
    // Transfer
    try await alice.transfer(amount: 300, to: bob)
    print("\nAfter Alice transfers $300 to Bob:")
    print("  Alice: $\(await alice.balance)")
    print("  Bob:   $\(await bob.balance)")
    // Intentional error: overdraft
    print("\nAttempting overdraft ($9999 from Bob)...")
    do {
        try await bob.withdraw(amount: 9999)
    } catch BankError.insufficientFunds(let requested, let available) {
        print("  ❌ Failed: requested $\(requested), only $\(available) available")
    }
    // Concurrent deposits, both hit Alice at the same time.
    // The actor serialises them safely, no data race.
    print("\nRunning 5 concurrent $10 deposits into Alice's account...")
    await withTaskGroup(of: Void.self) { group in
        for i in 1...5 {
            group.addTask {
                try? await alice.deposit(amount: 10)
                print("  Deposit \(i) completed")
            }
        }
    }
    print("  Alice final balance: $\(await alice.balance)")
}
